import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.Vng7Hdlh.js";const u=JSON.parse('{"title":"Spec: Prompt Caching & Token Tracking","description":"","frontmatter":{},"headers":[],"relativePath":"spec/11_prompt_caching.md","filePath":"spec/11_prompt_caching.md","lastUpdated":1775402800000}'),o={name:"spec/11_prompt_caching.md"};function c(i,e,l,p,r,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="spec-prompt-caching-token-tracking" tabindex="-1">Spec: Prompt Caching &amp; Token Tracking <a class="header-anchor" href="#spec-prompt-caching-token-tracking" aria-label="Permalink to &quot;Spec: Prompt Caching &amp; Token Tracking&quot;">​</a></h1><p><strong>Status</strong>: ✅ Done <strong>Rust crate</strong>: <code>piko-agent</code>, <code>piko-api</code><strong>TS source</strong>: <code>utils/promptCaching.ts</code>, <code>bootstrap/state.ts</code></p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Prompt caching reduces API costs by marking stable portions of the prompt as cacheable. Token usage is tracked cumulatively and displayed in the TUI status bar.</p><hr><h2 id="what-s-implemented" tabindex="-1">What&#39;s Implemented <a class="header-anchor" href="#what-s-implemented" aria-label="Permalink to &quot;What&#39;s Implemented&quot;">​</a></h2><h3 id="prompt-caching-✅" tabindex="-1">Prompt Caching ✅ <a class="header-anchor" href="#prompt-caching-✅" aria-label="Permalink to &quot;Prompt Caching ✅&quot;">​</a></h3><ul><li>[x] <code>cache_control: { type: &quot;ephemeral&quot; }</code> injected on: <ul><li>System prompt (last block of system array)</li><li>Last tool result in message history</li><li>Last user message</li></ul></li><li>[x] Cache read tokens tracked separately from regular input tokens</li><li>[x] Cache creation tokens tracked separately</li></ul><h3 id="token-tracking-✅" tabindex="-1">Token Tracking ✅ <a class="header-anchor" href="#token-tracking-✅" aria-label="Permalink to &quot;Token Tracking ✅&quot;">​</a></h3><ul><li>[x] Per-turn token counts from <code>usage</code> field in API response</li><li>[x] Cumulative session totals: <code>input_tokens</code>, <code>output_tokens</code>, <code>cache_creation_input_tokens</code>, <code>cache_read_input_tokens</code></li><li>[x] Displayed in TUI status bar: <code>in: X | out: Y | cache↑: Z | cache↓: W</code></li><li>[x] <code>TokenUsage</code> event emitted from agent loop after each turn</li></ul><hr><h2 id="spec-technical-details" tabindex="-1">Spec / Technical Details <a class="header-anchor" href="#spec-technical-details" aria-label="Permalink to &quot;Spec / Technical Details&quot;">​</a></h2><h3 id="cache-control-injection-points" tabindex="-1">Cache Control Injection Points <a class="header-anchor" href="#cache-control-injection-points" aria-label="Permalink to &quot;Cache Control Injection Points&quot;">​</a></h3><p>The Anthropic API caches the prefix of the prompt up to the last <code>cache_control</code> marker. To maximize cache hits:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System: [</span></span>
<span class="line"><span>  { text: &quot;base system prompt...&quot; },</span></span>
<span class="line"><span>  { text: &quot;CLAUDE.md content...&quot;, cache_control: { type: &quot;ephemeral&quot; } }  ← cache here</span></span>
<span class="line"><span>]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Messages: [</span></span>
<span class="line"><span>  { role: &quot;user&quot;,      content: &quot;...&quot; },</span></span>
<span class="line"><span>  { role: &quot;assistant&quot;, content: [...] },</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>  { role: &quot;user&quot;,      content: [</span></span>
<span class="line"><span>    { type: &quot;tool_result&quot;, ... },</span></span>
<span class="line"><span>    { type: &quot;tool_result&quot;, ..., cache_control: { type: &quot;ephemeral&quot; } },  ← cache here</span></span>
<span class="line"><span>    { type: &quot;text&quot;, text: &quot;user&#39;s latest message&quot;, cache_control: { type: &quot;ephemeral&quot; } }  ← cache here</span></span>
<span class="line"><span>  ]}</span></span>
<span class="line"><span>]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h3 id="token-display-format-status-bar" tabindex="-1">Token Display Format (Status Bar) <a class="header-anchor" href="#token-display-format-status-bar" aria-label="Permalink to &quot;Token Display Format (Status Bar)&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>↑12.3k ↓2.1k ⚡3.4k(cached)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Where:</p><ul><li><code>↑</code> = input tokens sent this session</li><li><code>↓</code> = output tokens generated</li><li><code>⚡</code> = cache read tokens (cheap, ~10% of input price)</li><li><code>cache↑</code> = cache write tokens (slightly more expensive than input)</li></ul><hr><h2 id="gaps-todos" tabindex="-1">Gaps / Todos <a class="header-anchor" href="#gaps-todos" aria-label="Permalink to &quot;Gaps / Todos&quot;">​</a></h2><ul><li><p>[ ] <strong>Cost calculation</strong> — convert token counts to USD based on model pricing table.</p><ul><li>Show total session cost in <code>/cost</code> command.</li><li>Model pricing should be a static table in code (updated when Anthropic changes prices).</li><li><code>claude-opus-4-6</code>: $15/$75 per M tokens (input/output)</li><li><code>claude-sonnet-4-6</code>: $3/$15 per M tokens</li><li><code>claude-haiku-4-5</code>: $0.25/$1.25 per M tokens</li></ul></li><li><p>[ ] <strong>Cache efficiency display</strong> — show cache hit rate (cache_read / total_input as %) in <code>/stats</code> or status bar tooltip.</p></li><li><p>[ ] <strong>Smarter cache placement</strong> — currently cache markers placed at fixed positions. TS has more sophisticated logic: if tools list is long and stable, cache after tools too. Could improve cache hit rate for long sessions.</p></li><li><p>[ ] <strong><code>/compact</code> token savings display</strong> — after compaction, show how many tokens were freed.</p></li></ul>`,23)])])}const m=a(o,[["render",c]]);export{u as __pageData,m as default};
